import React, { useState, useEffect } from 'react';
import { XMarkIcon, CheckCircleIcon, XCircleIcon, MapPinIcon, CalendarIcon } from '@heroicons/react/24/outline';
import { adminAPI } from '../../services/api';
import toast from 'react-hot-toast';

const WorkerDetailsModal = ({ worker, onClose }) => {
  const [fullDetails, setFullDetails] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchWorkerDetails();
  }, [worker?.id]);

  const fetchWorkerDetails = async () => {
    try {
      if (worker?.id) {
        const response = await adminAPI.getWorkerDetails(worker.id);
        setFullDetails(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching worker details:', error);
      toast.error('Failed to load worker details');
    } finally {
      setLoading(false);
    }
  };

  if (!worker) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-lg max-w-2xl w-full max-h-96 overflow-y-auto">
        <div className="sticky top-0 flex items-center justify-between p-6 border-b bg-white">
          <h2 className="text-2xl font-bold text-gray-900">Worker Details</h2>
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-lg transition"
          >
            <XMarkIcon className="h-6 w-6 text-gray-600" />
          </button>
        </div>

        <div className="p-6 space-y-6">
          {loading ? (
            <div className="flex items-center justify-center h-48">
              <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
            </div>
          ) : fullDetails ? (
            <>
              {/* Personal Information */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Personal Information</h3>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm text-gray-600">Name</p>
                    <p className="font-medium text-gray-900">{fullDetails.worker?.name}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Email</p>
                    <p className="font-medium text-gray-900">{fullDetails.worker?.email}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Phone</p>
                    <p className="font-medium text-gray-900">{fullDetails.worker?.phone}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-600">Status</p>
                    <div className="flex items-center mt-1">
                      {fullDetails.worker?.status === 'active' ? (
                        <>
                          <CheckCircleIcon className="h-5 w-5 text-green-600 mr-2" />
                          <span className="font-medium text-green-600">Active</span>
                        </>
                      ) : (
                        <>
                          <XCircleIcon className="h-5 w-5 text-red-600 mr-2" />
                          <span className="font-medium text-red-600">Inactive</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              {/* Location Information */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Current Location</h3>
                <div className="bg-blue-50 p-4 rounded-lg">
                  <div className="flex items-start">
                    <MapPinIcon className="h-5 w-5 text-blue-600 mr-3 mt-1" />
                    <div className="flex-1">
                      <p className="font-medium text-gray-900">
                        {fullDetails.worker?.location?.currentLocation?.address || 'Location not set'}
                      </p>
                      <p className="text-sm text-gray-600">
                        {fullDetails.worker?.location?.currentLocation?.city}, {fullDetails.worker?.location?.currentLocation?.state}
                      </p>
                      <p className="text-xs text-gray-500 mt-2">
                        Working Region: {fullDetails.worker?.location?.workingRegion || 'Not specified'}
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Weather Information */}
              {fullDetails.currentWeather && (
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Current Weather</h3>
                  <div className="bg-yellow-50 p-4 rounded-lg">
                    <div className="grid grid-cols-2 gap-4 text-sm">
                      {fullDetails.currentWeather.weather && (
                        <>
                          <div>
                            <p className="text-gray-600">Condition</p>
                            <p className="font-medium">{fullDetails.currentWeather.weather.conditions || 'Clear'}</p>
                          </div>
                          <div>
                            <p className="text-gray-600">Temperature</p>
                            <p className="font-medium">{fullDetails.currentWeather.weather.temperature || 'N/A'}°C</p>
                          </div>
                          <div>
                            <p className="text-gray-600">Rainfall</p>
                            <p className="font-medium">{fullDetails.currentWeather.weather.rainfall || 0} mm/hr</p>
                          </div>
                          <div>
                            <p className="text-gray-600">Wind Speed</p>
                            <p className="font-medium">{fullDetails.currentWeather.weather.windSpeed || 0} km/hr</p>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              )}

              {/* Premium Payment Status */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Premium Payment</h3>
                <div className={`p-4 rounded-lg ${fullDetails.premiumStatus?.currentWeekPaid ? 'bg-green-50' : 'bg-red-50'}`}>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm text-gray-600">Weekly Amount</p>
                      <p className="font-medium text-gray-900">₹{fullDetails.premiumStatus?.weeklyAmount || 0}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Current Week Status</p>
                      <div className="flex items-center mt-1">
                        {fullDetails.premiumStatus?.currentWeekPaid ? (
                          <>
                            <CheckCircleIcon className="h-5 w-5 text-green-600 mr-2" />
                            <span className="font-medium text-green-600">Paid</span>
                          </>
                        ) : (
                          <>
                            <XCircleIcon className="h-5 w-5 text-red-600 mr-2" />
                            <span className="font-medium text-red-600">Due</span>
                          </>
                        )}
                      </div>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Last Payment Date</p>
                      <p className="font-medium text-gray-900">
                        {fullDetails.premiumStatus?.lastPaymentDate
                          ? new Date(fullDetails.premiumStatus.lastPaymentDate).toLocaleDateString()
                          : 'N/A'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Next Payment Due</p>
                      <p className="font-medium text-gray-900">
                        {fullDetails.premiumStatus?.nextPaymentDue
                          ? new Date(fullDetails.premiumStatus.nextPaymentDue).toLocaleDateString()
                          : 'N/A'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Total Paid</p>
                      <p className="font-medium text-gray-900">₹{fullDetails.premiumStatus?.totalPaid || 0}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Missed Payments</p>
                      <p className="font-medium text-red-600">{fullDetails.premiumStatus?.missedPayments || 0}</p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Active Policies */}
              {fullDetails.policies && fullDetails.policies.length > 0 && (
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Policies</h3>
                  <div className="space-y-2">
                    {fullDetails.policies.map((policy) => (
                      <div key={policy._id} className="bg-gray-50 p-3 rounded">
                        <div className="flex items-center justify-between">
                          <div>
                            <p className="font-medium text-gray-900">{policy.policyNumber}</p>
                            <p className="text-sm text-gray-600">{policy.policyType}</p>
                          </div>
                          <div>
                            <span
                              className={`px-3 py-1 rounded text-sm font-medium ${
                                policy.status.current === 'active'
                                  ? 'bg-green-100 text-green-800'
                                  : 'bg-gray-100 text-gray-800'
                              }`}
                            >
                              {policy.status.current}
                            </span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </>
          ) : (
            <div className="text-center text-gray-500">Failed to load worker details</div>
          )}
        </div>

        <div className="sticky bottom-0 flex justify-end gap-3 p-6 border-t bg-white">
          <button
            onClick={onClose}
            className="btn-outline"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

export default WorkerDetailsModal;
